let ctx={channels:[],roles:[],emojis:[]},lastTextField=null,assetToken='',thumbnailAssetToken='',emojiTimer=null,savedAssets={},savedAssetPreviews={},uploadedGifs={};const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];
function toast(s){const t=$('#toast');t.textContent=s;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2500)}
let confirmResolver=null;function confirmAction(message,title='Are you sure?'){const modal=$('#confirm-modal');$('#confirm-title').textContent=title;$('#confirm-message').textContent=message;modal.hidden=false;return new Promise(resolve=>confirmResolver=resolve)}function closeConfirmModal(answer){$('#confirm-modal').hidden=true;if(confirmResolver){confirmResolver(answer);confirmResolver=null}}
async function api(path,method='GET',body){if(method==='PUT'&&/settings\/(welcome|leave|boost|birthdays)$/.test(path)&&body?.embed){const keys=['welcome','leave','boost','birthdays'],key=path.split('/').pop(),card=$$('.announcement-card')[keys.indexOf(key)];if(card){body.embed.image_asset=card.dataset.imageAsset||'';body.embed.thumbnail_asset=card.dataset.thumbAsset||''}}const r=await fetch(path,{method,headers:{'Content-Type':'application/json'},body:body?JSON.stringify(body):null});const raw=await r.text();let x={};try{x=raw?JSON.parse(raw):{}}catch{throw Error(r.ok?'The server returned an invalid response.':`Server error ${r.status}. Check the bot console for details.`)}if(!r.ok)throw Error(x.error||`Request failed (${r.status})`);return x}
function gid(){return $('#guild').value}function openPage(id){$$('.page,.nav').forEach(x=>x.classList.remove('active'));$('#'+id).classList.add('active');$(`.nav[data-page="${id}"]`)?.classList.add('active');$('#page-title').textContent=$(`.nav[data-page="${id}"]`)?.textContent||'Overview';if(id==='bot-embeds'&&botEmbedLoadedGuild!==gid())loadBotEmbeds();if(id==='other')loadBirthdays();if(id==='emojis')loadCommands();if(id==='glue')loadGlueSettings();if(id==='logs')loadActionLogs()}
$$('.nav').forEach(b=>b.onclick=()=>openPage(b.dataset.page));$('#guild').onchange=loadContext;
async function loadContext(silent=false){try{const oldGuild=ctx.guild?.id;ctx=await api(`/api/guild/${gid()}/context`);$('#channel-count').textContent=ctx.channels.length;$('#role-count').textContent=ctx.roles.length;$('#emoji-count').textContent=ctx.emojis.length;renderEmojiCapacity(ctx.emoji_capacity);if($('#bot-profile-name')){$('#bot-profile-name').value=ctx.bot_profile?.name||'';$('#bot-profile-preview').src=ctx.bot_profile?.avatar||''}applyBotIdentity();const texts=ctx.channels.filter(c=>c.type==='text'),cats=ctx.channels.filter(c=>c.type==='category');$$('.channels').forEach(s=>s.innerHTML=texts.map(c=>`<option value="${c.id}"># ${c.name}</option>`).join(''));if($('#birthday-announcement-channel'))$('#birthday-announcement-channel').insertAdjacentHTML('afterbegin','<option value="">Use default birthday channel</option>');$$('.categories').forEach(s=>s.innerHTML=`<option value="">No category</option>`+cats.map(c=>`<option value="${c.id}">${c.name}</option>`).join(''));$$('.roles').forEach(s=>s.innerHTML=ctx.roles.map(r=>`<option value="${r.id}">@${r.name}</option>`).join(''));$$('.emoji-strip').forEach(e=>e.innerHTML=ctx.emojis.map(x=>emojiCard(x,true)).join(''));$$('.emoji-strip [data-code]').forEach(i=>i.onclick=()=>insertEmoji(i.dataset.code,$('#embed-description')));renderEmojiLibrary();renderEmojiDrawer($('#emoji-search').value);if(!silent||oldGuild!==ctx.guild.id){loadAnnouncements();loadCommunitySystems();loadAbouts();loadActionLogs();if(!$('.ticket-option'))addTicketOption();if(!$('.role-option'))addRoleOption()}preview();renderTicketPreviews();renderRolePreview();if(!silent)toast(`${ctx.emojis.length} custom emojis loaded`)}catch(e){if(!silent)toast(e.message)}}
function insertEmoji(code,target=lastTextField){if(target&&['INPUT','TEXTAREA'].includes(target.tagName)&&target.type!=='color'){const start=target.selectionStart??target.value.length,end=target.selectionEnd??start;target.value=target.value.slice(0,start)+code+target.value.slice(end);target.focus();target.setSelectionRange(start+code.length,start+code.length);target.dispatchEvent(new Event('input',{bubbles:true}));toast('Emoji inserted')}else navigator.clipboard.writeText(code).then(()=>toast('Emoji code copied'))}
function emojiCard(x,compact=false){return `<button type="button" class="${compact?'drawer-emoji':'emoji-item'}" data-code="${x.text}" title="${x.text}"><img src="${x.proxy_url||x.url}" data-fallback="${x.url}" alt=":${x.name}:"><span>:${x.name}:</span><code>${x.text}</code>${x.animated?'<small>GIF</small>':''}</button>`}
function renderEmojiCapacity(cap=ctx.emoji_capacity){if(!$('#emoji-capacity')||!cap)return;$('#emoji-capacity').textContent=`Static: ${cap.static_used}/${cap.limit_per_type} · ${cap.static_available} slots available   |   Animated: ${cap.animated_used}/${cap.limit_per_type} · ${cap.animated_available} slots available`}
function renderEmojiLibrary(){const box=$('#emoji-library');if(!box)return;const groups=[["Static emojis",ctx.emojis.filter(x=>!x.animated)],["Animated emojis",ctx.emojis.filter(x=>x.animated)]];box.innerHTML=groups.map(([title,items])=>items.length?`<div class="emoji-group"><h3>${title}</h3><div class="emoji-group-grid">${items.sort((a,b)=>a.name.localeCompare(b.name)).map(x=>`<article class="emoji-manage-card"><button type="button" data-code="${x.text}" title="Insert ${x.text}"><img src="${x.proxy_url||x.url}" data-fallback="${x.url}" alt=":${x.name}:"></button><input value="${escapeHtml(x.name)}" maxlength="32" aria-label="Emoji name"><div class="emoji-card-actions"><button type="button" class="secondary" data-rename="${x.id}">Rename</button><button type="button" class="danger-action" data-delete="${x.id}" data-name="${escapeHtml(x.name)}">Delete</button></div><code>${x.text}</code></article>`).join('')}</div></div>`:'').join('')||'<p>No custom emojis found.</p>';box.querySelectorAll('[data-code]').forEach(e=>e.onclick=()=>insertEmoji(e.dataset.code));box.querySelectorAll('[data-rename]').forEach(b=>b.onclick=()=>renameServerEmoji(b.dataset.rename,b.closest('.emoji-manage-card').querySelector('input').value));box.querySelectorAll('[data-delete]').forEach(b=>b.onclick=()=>deleteServerEmoji(b.dataset.delete,b.dataset.name))}
function renderEmojiDrawer(filter=''){const q=filter.toLowerCase().trim(),items=ctx.emojis.filter(x=>x.name.toLowerCase().includes(q));$('#emoji-drawer-grid').innerHTML=items.map(x=>emojiCard(x,true)).join('')||'<p class="empty">No matching custom emojis.</p>';$$('#emoji-drawer-grid [data-code]').forEach(e=>e.onclick=()=>insertEmoji(e.dataset.code))}
async function refreshEmojis(showNotice=false){try{const x=await api(`/api/guild/${gid()}/emojis`);const changed=JSON.stringify(x.emojis.map(e=>e.id))!==JSON.stringify(ctx.emojis.map(e=>e.id));ctx.emojis=x.emojis;ctx.emoji_capacity=x.capacity;renderEmojiCapacity();$('#emoji-count').textContent=ctx.emojis.length;$$('.emoji-strip').forEach(e=>e.innerHTML=ctx.emojis.map(x=>emojiCard(x,true)).join(''));$$('.emoji-strip [data-code]').forEach(i=>i.onclick=()=>insertEmoji(i.dataset.code));renderEmojiLibrary();renderEmojiDrawer($('#emoji-search').value);preview();if(showNotice||changed)toast(`${ctx.emojis.length} custom emojis loaded`)}catch(e){if(showNotice)toast(e.message)}}
document.addEventListener('focusin',e=>{if((e.target.matches('textarea')||e.target.matches('input[type="text"],input:not([type])'))&&!e.target.matches('#emoji-search'))lastTextField=e.target});
function toggleEmojiDrawer(open){$('#emoji-drawer').classList.toggle('open',open);$('#drawer-scrim').classList.toggle('open',open);$('#emoji-drawer').setAttribute('aria-hidden',String(!open));if(open)setTimeout(()=>$('#emoji-search').focus(),180)}
$('#emoji-drawer-button').onclick=()=>toggleEmojiDrawer(true);$('#emoji-close').onclick=()=>toggleEmojiDrawer(false);$('#emoji-refresh').onclick=()=>refreshEmojis(true);$('#drawer-scrim').onclick=()=>toggleEmojiDrawer(false);$('#emoji-search').oninput=e=>renderEmojiDrawer(e.target.value);document.addEventListener('keydown',e=>{if(e.key==='Escape')toggleEmojiDrawer(false)});
function embed(){return{title:$('#embed-title').value,description:$('#embed-description').value,color:$('#embed-color').value,image:$('#embed-image').value,thumbnail:$('#embed-thumb').value,footer:$('#embed-footer').value}}
function escapeHtml(s){return String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]))}
function renderDiscordText(text){const escaped=escapeHtml(text);return escaped.replace(/&lt;(a?):([A-Za-z0-9_]+):(\d+)&gt;/g,(all,a,name,id)=>{const known=ctx.emojis.find(e=>e.id===id),fallback=known?.url||`https://cdn.discordapp.com/emojis/${id}.${a?'gif':'webp'}?size=96&quality=lossless`,url=known?.proxy_url||`/api/emoji/${id}?animated=${a?1:0}`;return `<img class="inline-custom-emoji" src="${url}" data-fallback="${fallback}" alt=":${name}:" title="&lt;${a?'a':''}:${name}:${id}&gt;">`}).replace(/\n/g,'<br>')}
document.addEventListener('error',e=>{const img=e.target;if(img.tagName==='IMG'&&img.dataset.fallback&&!img.dataset.fallbackUsed){img.dataset.fallbackUsed='1';img.src=img.dataset.fallback}},true)
function preview(){const e=embed();$('#p-content').innerHTML=renderDiscordText($('#embed-content').value);$('#p-title').innerHTML=renderDiscordText(e.title||'Title');$('#p-description').innerHTML=renderDiscordText(e.description||'Your preview updates while you type.');$('#p-embed').style.borderColor=e.color;$('#p-footer').innerHTML=renderDiscordText(e.footer);if(!assetToken){$('#p-image').src=e.image;$('#p-image').style.display=e.image?'block':'none'}if(!thumbnailAssetToken){$('#p-thumb').src=e.thumbnail;$('#p-thumb').style.display=e.thumbnail?'block':'none'}}$$('#embeds input,#embeds textarea').forEach(x=>x.oninput=preview);
function clearEmbed(){$$('#embeds input,#embeds textarea').forEach(x=>{if(x.type!=='color')x.value='';if(x.id)localStorage.removeItem(`draft:${gid()}:${x.id}`)});assetToken='';thumbnailAssetToken='';$('#embed-file').value='';$('#embed-thumb-file').value='';$('#p-image').removeAttribute('src');$('#p-thumb').removeAttribute('src');$('#p-image').style.display='none';$('#p-thumb').style.display='none';preview();toast('Editor cleared')}
async function uploadFile(file,placement='image'){if(!file)return;const form=new FormData();form.append('file',file);const r=await fetch(`/api/guild/${gid()}/asset`,{method:'POST',body:form}),x=await r.json();if(!r.ok)throw Error(x.error||'Upload failed');const target=placement==='thumbnail'?$('#p-thumb'):$('#p-image');if(placement==='thumbnail')thumbnailAssetToken=x.asset_token;else assetToken=x.asset_token;target.src=URL.createObjectURL(file);target.style.display='block';toast(`${placement==='thumbnail'?'Thumbnail':'Large image'} ready`)}
async function uploadSavedAsset(file,key){if(!file)return;const form=new FormData();form.append('file',file);const r=await fetch(`/api/guild/${gid()}/asset`,{method:'POST',body:form}),x=await r.json();if(!r.ok)throw Error(x.error||'Upload failed');savedAssets[key]=x.asset_token;savedAssetPreviews[key]=URL.createObjectURL(file);toast('Saved image ready');renderTicketPreviews();renderRolePreview();renderSocialPreviews();return x}
function addSavedAssetPicker(inputId,key){const base=$('#'+inputId);if(!base||base.parentElement.querySelector('.saved-asset-file'))return;const f=document.createElement('input');f.type='file';f.accept='image/png,image/jpeg,image/gif,image/webp';f.className='saved-asset-file';f.onchange=e=>uploadSavedAsset(e.target.files[0],key).catch(e=>toast(e.message));base.insertAdjacentElement('afterend',f)}
function wireDrop(zoneId,inputId,placement){const zone=$(zoneId),input=$(inputId);input.onchange=e=>uploadFile(e.target.files[0],placement).catch(e=>toast(e.message));zone.ondragover=e=>{e.preventDefault();zone.classList.add('drag')};zone.ondragleave=()=>zone.classList.remove('drag');zone.ondrop=e=>{e.preventDefault();zone.classList.remove('drag');uploadFile(e.dataTransfer.files[0],placement).catch(e=>toast(e.message))}}wireDrop('#image-drop','#embed-file','image');wireDrop('#thumb-drop','#embed-thumb-file','thumbnail');
