async function loadEmbed(){try{const x=await api(`/api/guild/${gid()}/embed/load`,'POST',{channel_id:$('#embed-channel').value,message_id:$('#edit-message-id').value});$('#embed-channel').value=x.channel_id;$('#edit-message-id').value=x.message_id;$('#embed-content').value=x.content||'';$('#embed-title').value=x.embed.title||'';$('#embed-description').value=x.embed.description||'';$('#embed-color').value=x.embed.color||'#5865f2';$('#embed-image').value=x.embed.image||'';$('#embed-thumb').value=x.embed.thumbnail||'';$('#embed-footer').value=x.embed.footer||'';assetToken='';thumbnailAssetToken='';$('#message-buttons').innerHTML='';$('#message-menus').innerHTML='';(x.components?.buttons||[]).forEach(addMessageButton);(x.components?.menus||[]).forEach(addMessageMenu);preview();renderMessageButtons();toast('Message and components loaded')}catch(e){toast(e.message)}}
async function editEmbed(){try{await api(`/api/guild/${gid()}/embed/edit`,'POST',{channel_id:$('#embed-channel').value,message_id:$('#edit-message-id').value,content:$('#embed-content').value,embed:embed(),asset_token:assetToken,thumbnail_asset_token:thumbnailAssetToken,buttons:messageButtons(),menus:messageMenus(),replace_components:true});toast('Changes saved')}catch(e){toast(e.message)}}
async function loadAnnouncements(){const types=[['welcome','Welcome','When somebody joins.'],['leave','Leave','When somebody leaves.'],['boost','Boost','When somebody boosts.'],['birthdays','Birthday','At midnight in the selected timezone.']];const box=$('#announcement-cards');box.innerHTML='';for(const [key,title,desc] of types){let d=await api(`/api/guild/${gid()}/settings/${key}`),defaults={welcome:'Welcome {user} to **{server}**!',leave:'**{username}** left the server.',boost:'Thank you for boosting, {user}! 💜',birthdays:'Happy birthday {user}! 🎉'};let el=document.createElement('article');el.className='card announcement-card';el.innerHTML=`<div class="switch-row"><div><h3>${title}</h3><p>${desc}</p></div><input class="switch" type="checkbox" ${d.enabled?'checked':''}></div><label>Channel<select>${ctx.channels.filter(c=>c.type==='text').map(c=>`<option value="${c.id}" ${String(d.channel_id)===c.id?'selected':''}># ${c.name}</option>`).join('')}</select></label>${key==='birthdays'?`<label>Timezone<input class="ann-timezone" value="${d.timezone||'America/New_York'}"></label>`:''}<label>Normal message<textarea class="ann-content" rows="2">${d.content||defaults[key]}</textarea></label><label>Embed title<input class="ann-title" value="${d.embed?.title||''}"></label><label>Embed description<textarea class="ann-description" rows="3">${d.embed?.description||''}</textarea></label><div class="fields two"><label>Color<input class="ann-color" type="color" value="${d.embed?.color||'#5865f2'}"></label><label>Footer<input class="ann-footer" value="${d.embed?.footer||''}"></label></div><label>Author name<input class="ann-author" value="${d.embed?.author||''}"></label><div class="fields two"><label>Large image URL<input class="ann-image" value="${d.embed?.image||''}"></label><label>Thumbnail URL<input class="ann-thumb" value="${d.embed?.thumbnail||''}"></label></div><div class="emoji-strip">${ctx.emojis.map(x=>emojiCard(x,true)).join('')}</div><div class="mini-preview"></div><button>Save ${title}</button>`;const draw=()=>el.querySelector('.mini-preview').innerHTML=discordPreview(el.querySelector('.ann-content').value,el.querySelector('.ann-title').value,el.querySelector('.ann-description').value,[],{color:el.querySelector('.ann-color').value,footer:el.querySelector('.ann-footer').value,image:el.querySelector('.ann-image').value,thumbnail:el.querySelector('.ann-thumb').value});el.querySelectorAll('input,textarea').forEach(i=>i.oninput=draw);el.querySelectorAll('[data-code]').forEach(i=>i.onclick=()=>insertEmoji(i.dataset.code,lastTextField));draw();el.querySelector('button:last-child').onclick=async()=>{const payload={enabled:el.querySelector('.switch').checked,channel_id:el.querySelector('select').value,timezone:el.querySelector('.ann-timezone')?.value||'America/New_York',content:el.querySelector('.ann-content').value,embed:{title:el.querySelector('.ann-title').value,description:el.querySelector('.ann-description').value,color:el.querySelector('.ann-color').value,footer:el.querySelector('.ann-footer').value,author:el.querySelector('.ann-author').value,image:el.querySelector('.ann-image').value,thumbnail:el.querySelector('.ann-thumb').value}};await api(`/api/guild/${gid()}/settings/${key}`,'PUT',payload);toast(`${title} saved`)};box.append(el)}}
async function loadActionLogs(){if(!$('#logs-enabled'))return;try{const d=await api(`/api/guild/${gid()}/settings/action_logs`);$('#logs-enabled').checked=!!d.enabled;$('#logs-channel').value=d.channel_id||$('#logs-channel').value;$('#logs-member-join').checked=!!d.member_join;$('#logs-member-leave').checked=!!d.member_leave;$('#logs-message-delete').checked=!!d.message_delete;$('#logs-message-edit').checked=!!d.message_edit;$('#logs-voice').checked=!!d.voice;$('#logs-new-account-days').value=d.new_account_days??7;renderActionLogPreviews()}catch(e){toast(e.message)}}
async function saveActionLogs(){try{await api(`/api/guild/${gid()}/settings/action_logs`,'PUT',{enabled:$('#logs-enabled').checked,channel_id:$('#logs-channel').value,member_join:$('#logs-member-join').checked,member_leave:$('#logs-member-leave').checked,message_delete:$('#logs-message-delete').checked,message_edit:$('#logs-message-edit').checked,voice:$('#logs-voice').checked,new_account_days:Number($('#logs-new-account-days').value||7)});toast('Action logs saved')}catch(e){toast(e.message)}}
function renderActionLogPreviews(){const box=$('#logs-previews');if(!box)return;const identity={author:'Buncha Crunch · @bunchacrunch',authorIcon:'https://cdn.discordapp.com/embed/avatars/0.png'},preview=(label,title,description,color,fields=[])=>`<p class="eyebrow log-preview-label">${label}</p>${discordPreview('',title,description,[],{...identity,color,fields,footer:'Today at 12:32 AM'})}`;box.innerHTML=preview('MEMBER JOIN','Member joined','@Buncha Crunch — **64th to join**\n⚠️ **NEW ACCOUNT** — created **9 hours, 30 minutes and 34 seconds ago** ⚠️','#ed4245',[{name:'Account created',value:'Saturday, July 19, 2026 3:02 PM'}])+preview('MEMBER LEAVE','Member left','@Buncha Crunch left **Example Server**.','#ed4245',[{name:'Roles',value:'@Member @Events @Games'}])+preview('MESSAGE DELETE','Message deleted in #other','I have this too for some reason','#ed4245',[{name:'Attachments',value:'example-video.mov'}])+preview('MESSAGE EDIT','Message edited in #chat','@Buncha Crunch','#fee75c',[{name:'Before',value:'the name is what got me'},{name:'After',value:'The name is what got me'}])+preview('VOICE ACTIVITY','Joined a voice channel','@Buncha Crunch joined #General.','#57f287',[{name:'Channel',value:'#General'}])}
$$('#logs input').forEach(i=>i.addEventListener('input',renderActionLogPreviews));
function componentRow(buttons=[]){return buttons.length?`<div class="component-row">${buttons.map(b=>{const raw=b.label||'Button',m=raw.match(/<(a?):([A-Za-z0-9_]+):(\d+)>/),emoji=b.emoji||(m?m[0]:''),label=m?raw.replace(m[0],'').trim():raw;return `<button type="button" class="discord-component ${b.style||''}">${renderDiscordText(emoji)}<span>${escapeHtml(label||'Option')}</span></button>`}).join('')}</div>`:''}
function botPreviewName(){return ctx.bot_profile?.name||'Jane Doe'}function botAvatarMarkup(){const avatar=ctx.bot_profile?.avatar;return avatar?`<img src="${escapeHtml(avatar)}" alt="${escapeHtml(botPreviewName())}" onerror="this.remove();this.parentElement.textContent='${escapeHtml(botPreviewName().slice(0,1).toUpperCase()||'J')}'">`:escapeHtml(botPreviewName().slice(0,1).toUpperCase()||'J')}function botIdentityHeader(){return `<div class="avatar" data-bot-avatar>${botAvatarMarkup()}</div><div class="message"><b><span data-bot-name>${escapeHtml(botPreviewName())}</span> <span>APP</span></b>`}function applyBotIdentity(){$$('[data-bot-avatar]').forEach(x=>x.innerHTML=botAvatarMarkup());$$('[data-bot-name]').forEach(x=>x.textContent=botPreviewName())}
function discordPreview(content,title,description,buttons=[],extras={}){const fields=(extras.fields||[]).map(f=>`<div class="preview-field"><b>${escapeHtml(f.name)}</b><p>${renderDiscordText(f.value)}</p></div>`).join(''),author=extras.author?`<div class="preview-embed-author">${extras.authorIcon?`<img src="${escapeHtml(extras.authorIcon)}" alt="">`:''}<b>${escapeHtml(extras.author)}</b></div>`:'';const embed=title||description||extras.image||extras.thumbnail||extras.footer||author||fields?`<div class="discord-embed" style="border-color:${extras.color||'#5865f2'}">${extras.thumbnail?`<img class="embed-thumb" style="display:block" src="${escapeHtml(extras.thumbnail)}">`:''}${author}<h3>${renderDiscordText(title)}</h3><p>${renderDiscordText(description)}</p>${fields}${extras.image?`<img style="display:block" src="${escapeHtml(extras.image)}">`:''}${extras.footer?`<div class="embed-footer">${renderDiscordText(extras.footer)}</div>`:''}</div>`:'';return `<div class="discord compact-preview">${botIdentityHeader()}<p>${renderDiscordText(content)}</p>${embed}${componentRow(buttons)}${extras.components||''}</div></div>`}
function categoryOptions(){return `<option value="">Use default</option>`+ctx.channels.filter(c=>c.type==='category').map(c=>`<option value="${c.id}">${c.name}</option>`).join('')}function roleOptions(){return `<option value="">Choose role</option>`+ctx.roles.map(r=>`<option value="${r.id}">@${r.name}</option>`).join('')}
function addTicketOption(data={}){const row=document.createElement('div');row.className='builder-row ticket-option';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Label<input class="opt-label" value="${escapeHtml(data.label||'Support')}"></label><label>Emoji<input class="opt-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><label>Description<input class="opt-description" maxlength="100" value="${escapeHtml(data.description||'')}"></label><div class="fields two"><label>Category<select class="opt-category">${categoryOptions()}</select></label><label>Staff role<select class="opt-role">${roleOptions()}</select></label></div><label>Channel prefix<input class="opt-prefix" value="${escapeHtml(data.channel_prefix||'ticket')}"></label>`;row.querySelector('.opt-category').value=data.category_id||'';row.querySelector('.opt-role').value=data.staff_role_id||'';row.querySelector('.remove-option').onclick=()=>{row.remove();renderTicketPreviews()};row.querySelectorAll('input,select').forEach(i=>i.oninput=renderTicketPreviews);$('#ticket-options').append(row);renderTicketPreviews()}
function ticketChoices(){return $$('.ticket-option').map(r=>({label:r.querySelector('.opt-label').value,emoji:r.querySelector('.opt-emoji').value,description:r.querySelector('.opt-description').value,category_id:r.querySelector('.opt-category').value,staff_role_id:r.querySelector('.opt-role').value,channel_prefix:r.querySelector('.opt-prefix').value}))}
function addRoleOption(data={}){const row=document.createElement('div');row.className='builder-row role-option';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Button/menu label<input class="opt-label" value="${escapeHtml(data.label||'Member')}"></label><label>Emoji<input class="opt-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><label>Description<input class="opt-description" maxlength="100" value="${escapeHtml(data.description||'')}"></label><label>Role to give<select class="opt-role">${roleOptions()}</select></label>`;row.querySelector('.opt-role').value=data.role_id||'';row.querySelector('.remove-option').onclick=()=>{row.remove();renderRolePreview()};row.querySelectorAll('input,select').forEach(i=>i.oninput=renderRolePreview);$('#role-options').append(row);renderRolePreview()}
