function renderTicketPreviews(){if(!$('#ticket-previews'))return;const choices=ticketChoices(),mode=$('#ticket-mode').value,menu=mode==='select'?`<div class="discord-select-preview">${renderDiscordText($('#ticket-placeholder').value||'Choose a ticket type')}<span>⌄</span></div><div class="select-preview-options">${choices.map(c=>`<div>${renderDiscordText(c.emoji)} <b>${escapeHtml(c.label)}</b><small>${escapeHtml(c.description)}</small></div>`).join('')}</div>`:'';const controls=mode==='select'?[]:[{label:$('#ticket-label').value||'Open ticket',emoji:$('#ticket-emoji').value}];$('#ticket-previews').innerHTML=`<p class="eyebrow">PANEL PREVIEW</p>${discordPreview($('#ticket-content').value,$('#ticket-title').value,$('#ticket-description').value,controls,{color:$('#ticket-color').value,image:savedAssetPreviews.ticketImage||$('#ticket-image').value,thumbnail:savedAssetPreviews.ticketThumb||$('#ticket-thumb').value,footer:$('#ticket-footer').value,components:menu})}<p class="eyebrow preview-gap">FIRST TICKET MESSAGE</p>${discordPreview($('#ticket-open-content').value,$('#ticket-open-title').value,$('#ticket-open-description').value,[{label:'Claim'},{label:'Close',style:'danger'}],{color:$('#ticket-open-color').value,image:savedAssetPreviews.ticketOpenImage||$('#ticket-open-image').value,thumbnail:savedAssetPreviews.ticketOpenThumb||$('#ticket-open-thumb').value,footer:$('#ticket-open-footer').value})}`}
