function renderRolePreview(){if(!$('#role-preview'))return;const choices=roleChoices(),selectMode=$('#rr-mode').value==='select',buttons=selectMode?[]:choices.map(c=>({label:c.label,emoji:c.emoji})),menu=selectMode?`<div class="discord-select-preview">${renderDiscordText($('#rr-placeholder').value||'Choose your roles')}<span>⌄</span></div><div class="select-preview-options">${choices.map(c=>`<div>${renderDiscordText(c.emoji)} <b>${escapeHtml(c.label)}</b><small>${escapeHtml(c.description)}</small></div>`).join('')}</div>`:'';$('#role-preview').innerHTML=`<p class="eyebrow">DISCORD PREVIEW</p>${discordPreview($('#rr-content').value,$('#rr-title').value,$('#rr-description').value,buttons,{color:$('#rr-color').value,image:savedAssetPreviews.roleImage||$('#rr-image').value,thumbnail:savedAssetPreviews.roleThumb||$('#rr-thumb').value,footer:$('#rr-footer').value,components:menu})}`}
