async function createTicketPanel(){try{await api(`/api/guild/${gid()}/ticket-panel`,'POST',{channel_id:$('#ticket-channel').value,mode:$('#ticket-mode').value,placeholder:$('#ticket-placeholder').value,category_id:$('#ticket-category').value,staff_role_id:$('#ticket-role').value,button_label:$('#ticket-label').value,button_emoji:$('#ticket-emoji').value,content:$('#ticket-content').value,embed:{title:$('#ticket-title').value,description:$('#ticket-description').value,color:$('#ticket-color').value,image:$('#ticket-image').value,thumbnail:$('#ticket-thumb').value,image_asset:savedAssets.ticketImage,thumbnail_asset:savedAssets.ticketThumb,footer:$('#ticket-footer').value},options:ticketChoices(),open_content:$('#ticket-open-content').value,open_embed:{title:$('#ticket-open-title').value,description:$('#ticket-open-description').value,color:$('#ticket-open-color').value,image:$('#ticket-open-image').value,thumbnail:$('#ticket-open-thumb').value,image_asset:savedAssets.ticketOpenImage,thumbnail_asset:savedAssets.ticketOpenThumb,footer:$('#ticket-open-footer').value}});toast('Ticket panel published')}catch(e){toast(e.message)}}
