function pollValues(){return $$('.poll-option').map(r=>r.querySelector('input').value.trim()).filter(Boolean)}function renderCommunity(){const opts=pollValues().slice(0,5);$('#poll-preview').innerHTML=discordPreview('',$('#poll-question').value||'Poll question',$('#poll-embed-description')?.value||'Choose an option below.',opts.map(label=>({label})),{color:$('#poll-color')?.value,image:savedAssetPreviews.pollImage||$('#poll-image')?.value,thumbnail:savedAssetPreviews.pollThumb||$('#poll-thumb')?.value,footer:$('#poll-footer')?.value});$('#event-preview').innerHTML=discordPreview('', $('#event-name').value||'Scheduled event',`${$('#event-description').value}\nLocation: ${$('#event-location').value||'Not set'} · starts in ${$('#event-start').value||60} minutes`,eventButtons())}$$('#community input,#community textarea').forEach(i=>i.addEventListener('input',renderCommunity));renderCommunity();
