function setVisualCropShape(shape){if(!imageEditSource)return;const b=cropImageBounds();if(shape==='full')return resetDirectCrop();const ratio=shape==='banner'?16/5:1;let w=b.w*.82,h=w/ratio;if(h>b.h*.82){h=b.h*.82;w=h*ratio}Object.assign(visualCrop,{x:b.x+(b.w-w)/2,y:b.y+(b.h-h)/2,w,h,action:''});paintDirectCrop()}
