editGlueItem=function(i){const g=glueCache[i];if(!g)return;$('#glue-id').value=g.id;$('#glue-channel').value=g.channel_id;$('#glue-content').value=g.content||'';$('#glue-title').value=g.embed?.title||'';$('#glue-embed-description').value=g.embed?.description||'';$('#glue-color').value=g.embed?.color||'#5865f2';$('#glue-footer').value=g.embed?.footer||'';$('#glue-image').value=g.embed?.image||'';$('#glue-thumb').value=g.embed?.thumbnail||'';if($('#glue-template-enabled'))$('#glue-template-enabled').checked=!!g.template_enabled;if($('#glue-template'))$('#glue-template').value=g.template||'';if($('#glue-button-label'))$('#glue-button-label').value=g.button_label||'Show template';if($('#glue-button-emoji'))$('#glue-button-emoji').value=g.button_emoji||''};
saveGlue=async function(){try{await api(`/api/guild/${gid()}/glue`,'POST',{id:$('#glue-id').value||null,channel_id:$('#glue-channel').value,content:$('#glue-content').value,template_enabled:!!$('#glue-template-enabled')?.checked,template:$('#glue-template')?.value||'',button_label:$('#glue-button-label')?.value||'Show template',button_emoji:$('#glue-button-emoji')?.value||'',embed:{title:$('#glue-title').value,description:$('#glue-embed-description').value,color:$('#glue-color').value,footer:$('#glue-footer').value,image:$('#glue-image').value,thumbnail:$('#glue-thumb').value}});clearGlueEditor();if($('#glue-template-enabled'))$('#glue-template-enabled').checked=false;if($('#glue-template'))$('#glue-template').value='';await loadGlueSettings();toast('Glued message and toggle settings saved')}catch(e){toast(e.message)}};
function installPersistentToggles(){$$('.announcement-card').forEach((card,index)=>{const save=card.querySelector(':scope > button:last-child'),key=['welcome','leave','boost','birthdays'][index],title=['Welcome','Leave','Boost','Birthday'][index];if(save&&!save.dataset.persistenceFixed){save.dataset.persistenceFixed='1';save.onclick=async()=>{const payload={enabled:card.querySelector(':scope .switch-row .switch').checked};payload.channel_id=card.querySelector(':scope > label select')?.value||'';payload.timezone=card.querySelector('.ann-timezone')?.value||'America/New_York';payload.content=card.querySelector('.ann-content').value;payload.embed={title:card.querySelector('.ann-title').value,description:card.querySelector('.ann-description').value,color:card.querySelector('.ann-color').value,footer:card.querySelector('.ann-footer').value,author:card.querySelector('.ann-author').value,image:card.querySelector('.ann-image').value,thumbnail:card.querySelector('.ann-thumb').value};await api(`/api/guild/${gid()}/settings/${key}`,'PUT',payload);toast(`${title} settings saved`)} }card.querySelectorAll('input[type="checkbox"]').forEach(toggle=>{if(toggle.dataset.autoSave)return;toggle.dataset.autoSave='1';toggle.addEventListener('change',()=>Promise.resolve(save?.onclick?.()).catch(e=>toast(e.message)))})});[['#logs input[type="checkbox"]',saveActionLogs],['#social #confess-enabled',saveConfessions]].forEach(([selector,saver])=>$$(selector).forEach(toggle=>{if(toggle.dataset.autoSave)return;toggle.dataset.autoSave='1';toggle.addEventListener('change',()=>Promise.resolve(saver()).catch(e=>toast(e.message))) }))}
const persistentToggleObserver=new MutationObserver(()=>{persistentToggleObserver.disconnect();installPersistentToggles();persistentToggleObserver.observe(document.body,{childList:true,subtree:true})});persistentToggleObserver.observe(document.body,{childList:true,subtree:true});installPersistentToggles();
